import{_ as e}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as i}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as o,o as l,c as n,a2 as r}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Token API Cloudflare","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/Safety/cloudflare-api-token.md","filePath":"it-IT/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),t={name:"it-IT/Safety/cloudflare-api-token.md"};function c(d,a,s,u,p,m){return l(),n("div",null,[...a[0]||(a[0]=[r('<h1 id="token-api-cloudflare" tabindex="-1">Token API Cloudflare <a class="header-anchor" href="#token-api-cloudflare" aria-label="Permalink to &quot;Token API Cloudflare&quot;">​</a></h1><p>Le credenziali API Cloudflare permettono a ImgBed di svuotare la cache CDN di Cloudflare dopo modifiche ai file.</p><p><img src="'+e+'" alt="Impostazioni Token API Cloudflare" loading="lazy"></p><h2 id="dove-configurare" tabindex="-1">Dove configurare <a class="header-anchor" href="#dove-configurare" aria-label="Permalink to &quot;Dove configurare&quot;">​</a></h2><p>Apri il pannello admin e vai a:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>Devi compilare:</p><ul><li>Zone ID</li><li>Email account</li><li>API Key</li></ul><h2 id="a-cosa-serve" tabindex="-1">A cosa serve <a class="header-anchor" href="#a-cosa-serve" aria-label="Permalink to &quot;A cosa serve&quot;">​</a></h2><p>Cloudflare può mettere in cache gli URL pubblici delle immagini.</p><p>La cache rende la distribuzione più veloce, ma può lasciare visibili contenuti vecchi per un po&#39; dopo eliminazione, blocco, sostituzione o spostamento di un file.</p><p>Quando le credenziali API Cloudflare sono configurate, ImgBed prova a svuotare la cache Cloudflare collegata al termine di queste operazioni.</p><p>È utile quando:</p><ul><li>elimini un&#39;immagine e vuoi che il link pubblico smetta di funzionare il prima possibile.</li><li>blocchi un&#39;immagine e vuoi impedire ai visitatori di vedere il file originale.</li><li>sostituisci un file con lo stesso nome e vuoi mostrare prima la nuova versione.</li><li>sposti o rinomini file e vuoi aggiornare rapidamente la cache dei vecchi percorsi.</li><li>cambi regole di accesso pubblico e vuoi aggiornare prima gallery pubblica o cache dell&#39;immagine casuale.</li></ul><h2 id="se-lo-lasci-vuoto" tabindex="-1">Se lo lasci vuoto <a class="header-anchor" href="#se-lo-lasci-vuoto" aria-label="Permalink to &quot;Se lo lasci vuoto&quot;">​</a></h2><p>ImgBed funziona normalmente anche senza questa impostazione.</p><p>La differenza è che ImgBed non svuoterà attivamente la cache CDN Cloudflare. I visitatori potrebbero vedere il contenuto vecchio finché la cache Cloudflare non scade da sola.</p><h2 id="trovare-lo-zone-id" tabindex="-1">Trovare lo Zone ID <a class="header-anchor" href="#trovare-lo-zone-id" aria-label="Permalink to &quot;Trovare lo Zone ID&quot;">​</a></h2><p>Lo Zone ID è lo Zone ID Cloudflare del sito usato dalla tua domain ImgBed.</p><ol><li>Accedi alla dashboard Cloudflare.</li><li>Apri il sito che contiene il dominio ImgBed.</li><li>Trova <code>Zone ID</code> nella pagina panoramica del sito.</li><li>Copialo nel campo <code>Zone ID</code> di ImgBed.</li></ol><p>È lo Zone ID del sito, non l&#39;Account ID.</p><h2 id="email-account" tabindex="-1">Email account <a class="header-anchor" href="#email-account" aria-label="Permalink to &quot;Email account&quot;">​</a></h2><p>Inserisci l&#39;indirizzo email con cui accedi a Cloudflare.</p><p>Deve corrispondere all&#39;API Key che inserisci sotto.</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>Inserisci la Cloudflare Global API Key.</p><ol><li>Accedi alla dashboard Cloudflare.</li><li>Apri il tuo profilo.</li><li>Vai alla pagina API Tokens.</li><li>Trova <code>Global API Key</code>.</li><li>Visualizzala e copiala.</li><li>Incollala nel campo <code>API Key</code> di ImgBed.</li></ol><p><img src="'+i+'" alt="Visualizza Global API Key" loading="lazy"></p><h2 id="quando-entra-in-funzione" tabindex="-1">Quando entra in funzione <a class="header-anchor" href="#quando-entra-in-funzione" aria-label="Permalink to &quot;Quando entra in funzione&quot;">​</a></h2><p>Dopo aver compilato i campi, salva le impostazioni.</p><p>Le modifiche future ai file proveranno automaticamente a svuotare la cache Cloudflare. Le operazioni passate non vengono gestite retroattivamente. Se hai eliminato o sostituito un file prima della configurazione, attendi la scadenza della cache o svuotala manualmente da Cloudflare.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="e-obbligatorio" tabindex="-1">È obbligatorio? <a class="header-anchor" href="#e-obbligatorio" aria-label="Permalink to &quot;È obbligatorio?&quot;">​</a></h3><p>No.</p><p>Se il tuo dominio non usa Cloudflare o non ti dà fastidio il ritardo della cache CDN, puoi lasciarlo vuoto.</p><h3 id="credenziali-sbagliate-bloccano-gli-upload" tabindex="-1">Credenziali sbagliate bloccano gli upload? <a class="header-anchor" href="#credenziali-sbagliate-bloccano-gli-upload" aria-label="Permalink to &quot;Credenziali sbagliate bloccano gli upload?&quot;">​</a></h3><p>Di solito no.</p><p>Credenziali errate impediscono solo lo svuotamento della cache Cloudflare. Upload e accesso normale ai file dovrebbero continuare a funzionare.</p><h3 id="perche-un-immagine-eliminata-si-apre-ancora" tabindex="-1">Perché un&#39;immagine eliminata si apre ancora? <a class="header-anchor" href="#perche-un-immagine-eliminata-si-apre-ancora" aria-label="Permalink to &quot;Perché un&#39;immagine eliminata si apre ancora?&quot;">​</a></h3><p>La causa più comune è che Cloudflare ha ancora il vecchio file in cache.</p><p>Con credenziali API Cloudflare corrette, ImgBed svuota la cache dell&#39;URL collegato quando un file viene eliminato.</p><h3 id="perche-vedo-ancora-la-vecchia-immagine-dopo-una-sostituzione" tabindex="-1">Perché vedo ancora la vecchia immagine dopo una sostituzione? <a class="header-anchor" href="#perche-vedo-ancora-la-vecchia-immagine-dopo-una-sostituzione" aria-label="Permalink to &quot;Perché vedo ancora la vecchia immagine dopo una sostituzione?&quot;">​</a></h3><p>Anche questo dipende spesso dalla cache CDN.</p><p>Dopo la configurazione, ImgBed prova a svuotare la cache del vecchio URL quando un file con lo stesso nome viene sovrascritto.</p>',44)])])}const g=o(t,[["render",c]]);export{b as __pageData,g as default};
